import { useContext } from "react";
import { AuthContext } from "./AuthContext";

export default function ClubHeader({
                                       club,
                                       activeTab = "overview",
                                       membership = { isMember: false, hasPending: false, isLeader: false },
                                       leaders = [],
                                       onJoin,
                                       onLeave,
                                       onCancelRequest
                                   }) {
    const { user } = useContext(AuthContext);

    if (!club) return null;

    const TABS = ["overview", "stats", "matches", "news", "members"];

    return (
        <header className="club-header">
            {/* ===== TOP ROW ===== */}
            <div className="club-header-top">
                {/* LEFT: LOGO + META */}
                <div className="club-header-left">
                    <img
                        src={club.logoUrl || "/default-club.png"}
                        alt={`${club.name} logo`}
                        className="club-logo"
                    />

                    <div className="club-meta">
                        <h1 className="club-title">
                            {club.name}
                            {club.shortName && (
                                <span className="club-short"> {club.shortName}</span>
                            )}
                        </h1>

                        {/* LEADERS */}
                        {leaders.length > 0 && (
                            <div className="club-leaders">
                                ⭐ Leader{leaders.length > 1 ? "s" : ""}:{" "}
                                <strong>{leaders.join(", ")}</strong>
                            </div>
                        )}

                        {/* DESCRIPTION */}
                        {club.description && (
                            <p className="club-description">
                                {club.description}
                            </p>
                        )}

                        {/* META LINKS */}
                        <div className="club-sub">
                            {club.website && (
                                <a
                                    href={club.website}
                                    target="_blank"
                                    rel="noreferrer"
                                >
                                    {club.website}
                                </a>
                            )}
                            {club.twitter && <span>@{club.twitter}</span>}
                            {club.country && <span>{club.country}</span>}
                        </div>
                    </div>
                </div>

                {/* RIGHT: MEMBERSHIP ACTION */}
                {user && (
                    <div className="club-member-pill">
                        <span className="club-member-user">
                            ⭐ {user.username}
                        </span>

                        {membership.isMember ? (
                            membership.isLeader ? (
                                <button
                                    className="pill-btn pill-disabled"
                                    disabled
                                    title="You are the club leader"
                                >
                                    Leader
                                </button>
                            ) : (
                                <button
                                    className="pill-btn pill-leave"
                                    onClick={onLeave}
                                >
                                    Leave
                                </button>
                            )
                        ) : membership.hasPending ? (
                            <button
                                className="pill-btn pill-pending"
                                onClick={onCancelRequest}
                            >
                                Pending
                            </button>
                        ) : (
                            <button
                                className="pill-btn pill-join"
                                onClick={onJoin}
                            >
                                Join
                            </button>
                        )}
                    </div>
                )}
            </div>

            {/* ===== TABS ===== */}
            <nav className="club-tabs">
                {TABS.map(tab => (
                    <a
                        key={tab}
                        href={`#/clubs/${club.id}/${tab}`}
                        className={activeTab === tab ? "active" : ""}
                        aria-current={activeTab === tab ? "page" : undefined}
                    >
                        {tab.toUpperCase()}
                    </a>
                ))}
            </nav>
        </header>
    );
}
